#### 方法一：深度优先搜索

**思路与算法**

我们使用「深度优先搜索」来解决这个这个问题，编写子函数 $\textit{dfs}(i, j, \textit{cur})$。

其中每个状态包含三个变量，$i$ 为 $\textit{nums}$ 中下一个元素，$j$ 为 $\textit{andValues}$ 中下一个匹配元素，$\textit{cur}$ 为当前子数组元素的按位与运算结果。

在每一次搜索中，我们计算更新 $\textit{cur}$。

- 如果当前 $\textit{cur}$ 小于 $\textit{andValues}[j]$，则匹配失败。
- 如果当前 $\textit{cur}$ 大于 $\textit{andValues}[j]$，则还需继续进行与运算，进入下一轮搜索。
- 如果当前 $\textit{cur}$ 等于 $\textit{andValues}[j]$，可以继续进行与运算，也可以开始匹配 $\textit{andValues}[j + 1]$。

每次搜索，我们返回找到的最小值，并存入记忆化搜索的数组中，以避免重复计算。

最后在主程序中调用，返回可能的最小子数组值之和。如果无法完成这样的划分，则返回 $-1$。

**代码**

```C++ [sol1-C++]
class Solution {
public:
    int minimumValueSum(vector<int>& nums, vector<int>& andValues) {
        int n = nums.size(), m = andValues.size();
        memo.resize(m * n);
        int res = dfs(0, 0, INF, nums, andValues);
        return res < INF ? res : -1;
    }

private:
    static const int INF = (1 << 20) - 1;
    vector<unordered_map<int, int>> memo;
    int dfs(int i, int j, int cur, vector<int>& nums, vector<int>& andValues) {
        int n = nums.size(), m = andValues.size(), key = i * m + j;
        if (i == n && j == m) return 0;
        if (i == n || j == m) return INF;
        if (memo[key].count(cur)) return memo[key][cur];

        cur &= nums[i];
        if ((cur & andValues[j]) < andValues[j]) return INF;

        int res = dfs(i + 1, j, cur, nums, andValues);
        if (cur == andValues[j]) {
            res = min(res, dfs(i + 1, j + 1, INF, nums, andValues) + nums[i]);
        }
        memo[key][cur] = res;
        return res;
    }
};
```

```C [sol1-C]
const int INF = (1 << 20) - 1;

typedef struct {
    int key;
    int val;
    UT_hash_handle hh;
} HashItem; 

HashItem *hashFindItem(HashItem **obj, int key) {
    HashItem *pEntry = NULL;
    HASH_FIND_INT(*obj, &key, pEntry);
    return pEntry;
}

bool hashAddItem(HashItem **obj, int key, int val) {
    if (hashFindItem(obj, key)) {
        return false;
    }
    HashItem *pEntry = (HashItem *)malloc(sizeof(HashItem));
    pEntry->key = key;
    pEntry->val = val;
    HASH_ADD_INT(*obj, key, pEntry);
    return true;
}

int hashGetItem(HashItem **obj, int key, int defaultVal) {
    HashItem *pEntry = hashFindItem(obj, key);
    if (!pEntry) {
        return defaultVal;
    }
    return pEntry->val;
}

void hashFree(HashItem **obj) {
    HashItem *curr = NULL, *tmp = NULL;
    HASH_ITER(hh, *obj, curr, tmp) {
        HASH_DEL(*obj, curr);  
        free(curr);
    }
}

int dfs(int i, int j, int cur, const int *nums, int numsSize,  const int *andValues, int andValuesSize, HashItem **memo) {
    int n = numsSize, m = andValuesSize, key = i * m + j;
    if (i == n && j == m) {
        return 0;
    }
    if (i == n || j == m) {
        return INF;
    }
    if (hashFindItem(&memo[key], cur)) {
        return hashGetItem(&memo[key], cur, 0);
    }

    cur &= nums[i];
    if ((cur & andValues[j]) < andValues[j]) {
        return INF;
    }
    int res = dfs(i + 1, j, cur, nums, numsSize, andValues, andValuesSize, memo);
    if (cur == andValues[j]) {
        res = fmin(res, dfs(i + 1, j + 1, INF, nums, numsSize, andValues, andValuesSize, memo) + nums[i]);
    }
    hashAddItem(&memo[key], cur, res);
    return res;
}

int minimumValueSum(int* nums, int numsSize, int* andValues, int andValuesSize) {
    int n = numsSize, m = andValuesSize;
    HashItem *memo[m * n];
    for (int i = 0; i < m * n; i++) {
        memo[i] = NULL;
    }
    int res = dfs(0, 0, INF, nums, numsSize, andValues, andValuesSize, memo);
    for (int i = 0; i < m * n; i++) {
        hashFree(&memo[i]);
    }
    return res < INF ? res : -1;
}
```

```Java [sol1-Java]
class Solution {
    private static final int INF = (1 << 20) - 1;
    private HashMap<Integer, Integer>[] memo;

    public int minimumValueSum(int[] nums, int[] andValues) {
        int n = nums.length, m = andValues.length;
        memo = new HashMap[m * n];
        for (int i = 0; i < m * n; ++i) {
            memo[i] = new HashMap<Integer, Integer>();
        }
        int res = dfs(0, 0, INF, nums, andValues);
        return res < INF ? res : -1;
    }

    private int dfs(int i, int j, int cur, int[] nums, int[] andValues) {
        int n = nums.length, m = andValues.length, key = i * m + j;
        if (i == nums.length && j == andValues.length) {
            return 0;
        }
        if (i == nums.length || j == andValues.length) {
            return INF;
        }
        if (memo[key].containsKey(cur)) {
            return memo[key].get(cur);
        }
        cur &= nums[i];
        if ((cur & andValues[j]) < andValues[j]) {
            return INF;
        }
        int res = dfs(i + 1, j, cur, nums, andValues);
        if (cur == andValues[j]) {
            res = Math.min(res, dfs(i + 1, j + 1, INF, nums, andValues) + nums[i]);
        }
        memo[key].put(cur, res);
        return res;
    }
}
